const LNG0 = 29.2, LNG1 = 40.6, LAT0 = -0.85, LAT1 = -11.85;

export function projectTz(lat: number, lng: number): { x: number; y: number } {
  return {
    x: ((lng - LNG0) / (LNG1 - LNG0)) * TZ_VIEW.w,
    y: ((LAT0 - lat) / (LAT0 - LAT1)) * TZ_VIEW.h,
  };
}

